#[cfg(feature = "R4")]
impl fhir_validation::r4::R4Validatable for ElementDefinitionSlicing {
    fn validate_bindings(
        &self,
        validator: &fhir_validation::Validator,
        terminology: Option<&dyn fhir_validation::TerminologyService>,
    ) -> Vec<fhir_validation::ValidationIssue> {
        let mut issues = Vec::new();
        issues.extend(validator.validate_bindings(self, ELEMENT_DEFINITION_SLICING_BINDINGS, terminology));

        for value in &self.discriminator {
            issues.extend(value.validate_bindings(validator, terminology));
        }
        issues
    }

    fn validate_invariants(
        &self,
        validator: &fhir_validation::Validator,
        evaluator: &dyn fhir_validation::InvariantEvaluator,
    ) -> Vec<fhir_validation::ValidationIssue> {
        let mut issues = Vec::new();
        issues.extend(validator.validate_invariants(self, ELEMENT_DEFINITION_SLICING_INVARIANTS, evaluator));

        for value in &self.extension {
            issues.extend(value.validate_invariants(validator, evaluator));
        }
        for value in &self.discriminator {
            issues.extend(value.validate_invariants(validator, evaluator));
        }
        issues
    }
}

